import{_ as t}from"./chunks/floatingball.D-BT0bmL.js";import{_ as l,a as i}from"./chunks/sidebar-chat-messages.symtOcQN.js";import{_ as r,o as e,c as o,ag as s}from"./chunks/framework.BqfgOMAh.js";const f=JSON.parse('{"title":"AI 对话","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/ai-chat.md","filePath":"zh/guide/ai-chat.md"}'),n={name:"zh/guide/ai-chat.md"};function d(h,a,u,c,p,g){return e(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="ai-对话" tabindex="-1">AI 对话 <a class="header-anchor" href="#ai-对话" aria-label="Permalink to &quot;AI 对话&quot;">​</a></h1><p>NexusFlow 的核心体验是通过 AI 对话来操作虚幻引擎蓝图。本页面详细介绍对话界面的各个部分和使用方法。</p><h2 id="悬浮球" tabindex="-1">悬浮球 <a class="header-anchor" href="#悬浮球" aria-label="Permalink to &quot;悬浮球&quot;">​</a></h2><p><img src="'+t+'" alt="NexusFlow 悬浮球"></p><p>悬浮球是 NexusFlow 在桌面上的快速入口，始终显示在屏幕上方。</p><ul><li><strong>外观</strong>：圆形按钮，UE 连接时蓝紫色渐变、未连接时灰色，中间显示 Nexus 网络图案 Logo。UE 未连接时右下角有红色小圆点提示</li><li><strong>点击</strong>：打开或切换到 AI 对话侧边栏</li><li><strong>拖拽</strong>：按住鼠标拖动可移动位置，松开后自动吸附到最近的屏幕边缘</li><li><strong>关闭</strong>：鼠标悬停时右上角显示关闭按钮（×），点击后弹出确认对话框</li><li><strong>隐藏</strong>：可以隐藏悬浮球，通过系统托盘图标恢复显示</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>拖动距离超过 5 像素才会被视为拖拽操作，短距离的触碰仍会触发点击打开侧边栏。</p></div><h2 id="侧边栏界面" tabindex="-1">侧边栏界面 <a class="header-anchor" href="#侧边栏界面" aria-label="Permalink to &quot;侧边栏界面&quot;">​</a></h2><p><img src="'+l+'" alt="AI 对话侧边栏 — 空状态"></p><p>侧边栏是 AI 对话的主界面，分为三个区域：</p><h3 id="顶部-header" tabindex="-1">顶部 Header <a class="header-anchor" href="#顶部-header" aria-label="Permalink to &quot;顶部 Header&quot;">​</a></h3><p>Header 区域包含以下功能：</p><table tabindex="0"><thead><tr><th>元素</th><th>说明</th></tr></thead><tbody><tr><td><strong>Logo + 标题</strong></td><td>显示 &quot;NexusFlow AI&quot;，连接 UE 后追加项目名称</td></tr><tr><td><strong>新建会话</strong></td><td>新建一个对话（会弹出确认对话框）</td></tr><tr><td><strong>模式切换</strong></td><td>切换窗口模式（浮动/停靠左侧/停靠右侧）</td></tr><tr><td><strong>快捷操作</strong></td><td>浮动模式下为「置顶」按钮；停靠模式下为「切换方向」按钮</td></tr><tr><td><strong>设置</strong></td><td>齿轮图标，打开设置页面</td></tr><tr><td><strong>关闭</strong></td><td>隐藏侧边栏</td></tr></tbody></table><p>在浮动模式下，可以按住 Header 区域拖动整个窗口。</p><h3 id="对话区域" tabindex="-1">对话区域 <a class="header-anchor" href="#对话区域" aria-label="Permalink to &quot;对话区域&quot;">​</a></h3><p><img src="'+i+'" alt="AI 对话侧边栏 — 对话示例"></p><p>中间的主内容区是与 AI 交流的对话界面：</p><ul><li><strong>消息展示</strong>：显示你和 AI 的对话历史</li><li><strong>初始消息</strong>：首次打开时，AI 会发送多语言自我介绍（根据你设置的 Agent 回复语言）</li><li><strong>工具调用</strong>：当 AI 执行蓝图操作时，你可以看到工具调用的实时状态</li><li><strong>停止生成</strong>：点击停止按钮可中断 AI 的回复生成</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>当 AI 正在执行工具操作（如修改蓝图）时，无法中断。此时点击停止会显示提示「工具正在执行中，无法中断」。</p></div><h3 id="底部状态栏" tabindex="-1">底部状态栏 <a class="header-anchor" href="#底部状态栏" aria-label="Permalink to &quot;底部状态栏&quot;">​</a></h3><p>状态栏显示连接状态和当前模型信息：</p><ul><li><strong>连接状态</strong>：🟢 绿色圆点表示 UE 已连接（显示项目名称和 UE 版本），🔴 红色圆点表示未连接</li><li><strong>当前模型</strong>：右侧显示当前活跃的 AI 模型名称</li><li><strong>状态消息</strong>：操作反馈（如编译结果等）会以临时横幅形式显示</li></ul><h2 id="窗口模式" tabindex="-1">窗口模式 <a class="header-anchor" href="#窗口模式" aria-label="Permalink to &quot;窗口模式&quot;">​</a></h2><p>侧边栏支持三种窗口模式，通过 Header 的模式切换菜单选择：</p><h3 id="浮动窗口-默认" tabindex="-1">浮动窗口（默认） <a class="header-anchor" href="#浮动窗口-默认" aria-label="Permalink to &quot;浮动窗口（默认）&quot;">​</a></h3><p>独立窗口，可自由拖动和调整大小：</p><ul><li>可以拖动 Header 移动窗口位置</li><li>支持窗口置顶（图钉按钮），使窗口始终在最前面</li><li>适合需要同时查看 UE 编辑器的场景</li></ul><h3 id="停靠左侧-停靠右侧" tabindex="-1">停靠左侧 / 停靠右侧 <a class="header-anchor" href="#停靠左侧-停靠右侧" aria-label="Permalink to &quot;停靠左侧 / 停靠右侧&quot;">​</a></h3><p>侧边栏自动贴靠到屏幕边缘，类似 VS Code 的侧边栏：</p><ul><li>自动占据屏幕一侧的全高度</li><li>可以拖拽边缘调整宽度</li><li>快捷按钮可一键切换停靠到另一侧</li><li>适合长时间使用对话功能的场景</li></ul><div class="tip custom-block"><p class="custom-block-title">快速切换</p><p>在停靠模式下，Header 上的方向箭头按钮可以快速将侧边栏切换到屏幕另一侧。</p></div><h2 id="对话能力" tabindex="-1">对话能力 <a class="header-anchor" href="#对话能力" aria-label="Permalink to &quot;对话能力&quot;">​</a></h2><h3 id="自然语言操作" tabindex="-1">自然语言操作 <a class="header-anchor" href="#自然语言操作" aria-label="Permalink to &quot;自然语言操作&quot;">​</a></h3><p>直接用自然语言描述你的需求，AI 会自动：</p><ul><li>读取当前蓝图的结构和节点信息</li><li>根据需求修改蓝图（添加/删除/修改节点和连线）</li><li>创建新的蓝图逻辑</li><li>管理变量、函数和事件</li></ul><h3 id="ue-上下文自动同步" tabindex="-1">UE 上下文自动同步 <a class="header-anchor" href="#ue-上下文自动同步" aria-label="Permalink to &quot;UE 上下文自动同步&quot;">​</a></h3><p>NexusFlow 会自动将 UE 编辑器的上下文同步给 AI，包括：</p><ul><li>连接状态和 UE 版本</li><li>当前项目名称</li><li>当前打开的蓝图信息</li><li>选中的节点和 Actor</li><li>编辑模式和活动窗口</li></ul><p>这意味着你不需要手动告诉 AI 你正在编辑哪个蓝图——它已经知道了。</p><h3 id="工具调用追踪" tabindex="-1">工具调用追踪 <a class="header-anchor" href="#工具调用追踪" aria-label="Permalink to &quot;工具调用追踪&quot;">​</a></h3><p>当 AI 需要操作蓝图时，会调用相应的工具。你可以在对话中看到：</p><ul><li>工具名称和参数</li><li>执行状态（进行中 / 成功 / 失败）</li><li>执行结果摘要</li></ul><h3 id="新建会话" tabindex="-1">新建会话 <a class="header-anchor" href="#新建会话" aria-label="Permalink to &quot;新建会话&quot;">​</a></h3><p>点击 Header 的新建会话按钮可以开始新的对话。由于当前版本不支持历史会话记录，新建会话会清除当前的对话内容，因此会弹出确认对话框。</p><h3 id="停止生成" tabindex="-1">停止生成 <a class="header-anchor" href="#停止生成" aria-label="Permalink to &quot;停止生成&quot;">​</a></h3><p>在 AI 回复过程中，点击停止按钮可以中断生成。但需要注意：</p><ul><li>✅ 可以停止：AI 正在生成文字回复时</li><li>❌ 无法停止：AI 正在执行工具操作时（如修改蓝图）</li></ul><h2 id="系统托盘" tabindex="-1">系统托盘 <a class="header-anchor" href="#系统托盘" aria-label="Permalink to &quot;系统托盘&quot;">​</a></h2><p>NexusFlow 在 Windows 系统托盘（任务栏右侧区域）放置了常驻图标。</p><ul><li><strong>恢复悬浮球</strong>：如果你隐藏了悬浮球，右键点击托盘图标可以恢复显示</li><li><strong>快捷入口</strong>：点击托盘图标可快速打开侧边栏</li></ul><div class="tip custom-block"><p class="custom-block-title">找不到托盘图标？</p><p>如果看不到 NexusFlow 图标，点击任务栏上的向上箭头（∧）展开隐藏图标区域。</p></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./quick-menu">UE 快速菜单</a> — 4 个入口、17 项 AI 操作，覆盖右键菜单和工具栏</li><li><a href="./blueprint-operations">蓝图操作</a> — 详细的蓝图操作示例和技巧</li><li><a href="./settings">设置说明</a> — 自定义窗口模式、快捷键等</li></ul>',53)])])}const x=r(n,[["render",d]]);export{f as __pageData,x as default};
